export function bidirectionalBfs(arr: number[]): number {
  if (arr.length < 4) return -1;

  const n = arr[0];
  const m = arr[1];
  const start = arr[2];
  const end = arr[3];

  if (arr.length < 4 + 2 * m) return -1;
  if (start === end) return 0;

  const adj: number[][] = Array.from({ length: n }, () => []);
  for (let i = 0; i < m; i++) {
    const u = arr[4 + 2 * i];
    const v = arr[4 + 2 * i + 1];
    if (u >= 0 && u < n && v >= 0 && v < n) {
      adj[u].push(v);
      adj[v].push(u);
    }
  }

  const distStart: number[] = new Array(n).fill(-1);
  const distEnd: number[] = new Array(n).fill(-1);

  const qStart: number[] = [start];
  distStart[start] = 0;

  const qEnd: number[] = [end];
  distEnd[end] = 0;

  let headStart = 0;
  let headEnd = 0;

  while (headStart < qStart.length && headEnd < qEnd.length) {
    // Start
    const u = qStart[headStart++];
    if (distEnd[u] !== -1) return distStart[u] + distEnd[u];

    for (const v of adj[u]) {
      if (distStart[v] === -1) {
        distStart[v] = distStart[u] + 1;
        if (distEnd[v] !== -1) return distStart[v] + distEnd[v];
        qStart.push(v);
      }
    }

    // End
    const w = qEnd[headEnd++];
    if (distStart[w] !== -1) return distStart[w] + distEnd[w];

    for (const v of adj[w]) {
      if (distEnd[v] === -1) {
        distEnd[v] = distEnd[w] + 1;
        if (distStart[v] !== -1) return distStart[v] + distEnd[v];
        qEnd.push(v);
      }
    }
  }

  return -1;
}

export function bidirectionalBfs(arr: number[]): number {
    const n = arr[0];
    const m = arr[1];
    const src = arr[2];
    const dst = arr[3];
    if (src === dst) return 0;

    const adj: number[][] = Array.from({ length: n }, () => []);
    for (let i = 0; i < m; i++) {
        const u = arr[4 + 2 * i];
        const v = arr[4 + 2 * i + 1];
        adj[u].push(v);
        adj[v].push(u);
    }

    const distS = new Array(n).fill(-1);
    const distT = new Array(n).fill(-1);
    distS[src] = 0;
    distT[dst] = 0;
    const qS: number[] = [src];
    const qT: number[] = [dst];
    let iS = 0, iT = 0;

    while (iS < qS.length || iT < qT.length) {
        if (iS < qS.length) {
            const u = qS[iS++];
            for (const v of adj[u]) {
                if (distS[v] === -1) {
                    distS[v] = distS[u] + 1;
                    qS.push(v);
                }
                if (distT[v] !== -1) return distS[v] + distT[v];
            }
        }
        if (iT < qT.length) {
            const u = qT[iT++];
            for (const v of adj[u]) {
                if (distT[v] === -1) {
                    distT[v] = distT[u] + 1;
                    qT.push(v);
                }
                if (distS[v] !== -1) return distS[v] + distT[v];
            }
        }
    }

    return -1;
}
